import { Modal } from './Modal'
import useModal from './useModal'
function Example() {
    const { openModal } = useModal()
    function openLow() {
        openModal({
            component: <Modal
                id='1'
                title="Low Priority"
                primaryAction={{ label: "OK", onClick: () => { } }}
                secondaryAction={{ label: "Cancel", onClick: () => { } }}
            >abc</Modal>,
            priority: 1
        })
    }
    function openHigh() {
        openModal({
            component: <Modal
                id='2'
                title="High Priority"
                primaryAction={{ label: "OK", onClick: () => { } }}
                secondaryAction={{ label: "Cancel", onClick: () => { } }}
            >abc</Modal>,
            priority: 10
        })
    }
    return (
        <div>
            <button onClick={openLow}>Open Low Priority Modal</button>
            <button onClick={openHigh}>Open High Priority Modal</button>
        </div>
    )
}

export default Example
